module edge_detector(  
    input wire clk,  
    input wire rst,  
    input wire signal,  
    output reg edge_detected  
);  

    reg unused_signal_d;  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            edge_detected <= 0;  
            unused_signal_d <= 0;  
        end else begin  
            edge_detected <= (signal && !unused_signal_d);  
            unused_signal_d <= signal;  
        end  
    end  
endmodule
